def normalize(name):
    # first letter of first word, ignoring punctuation
    # second word = letters only
    m = re.search(r"^\s*([A-Za-z])[A-Za-z''.-]*\s+([A-Za-z-]+)", name)
    if not m:
        print(f"Unable to handle {name}")
        return None
    return (m.group(1) + m.group(2)).lower()


